/* === UART HAL 层初始化（STM32F4xx HAL）=== */
#include "stm32f4xx_hal.h"

UART_HandleTypeDef huart1;

/* 初始化 UART1：115200 baud, 8N1, 无流控 */
int hal_uart_init(void) {
    __HAL_RCC_USART1_CLK_ENABLE();
    __HAL_RCC_GPIOA_CLK_ENABLE();

    /* PA9 = TX (AF7), PA10 = RX (AF7) */
    GPIO_InitTypeDef gpio = {0};
    gpio.Pin       = GPIO_PIN_9 | GPIO_PIN_10;
    gpio.Mode      = GPIO_MODE_AF_PP;
    gpio.Pull      = GPIO_PULLUP;
    gpio.Speed     = GPIO_SPEED_FREQ_HIGH;
    gpio.Alternate = GPIO_AF7_USART1;
    HAL_GPIO_Init(GPIOA, &gpio);

    huart1.Instance          = USART1;
    huart1.Init.BaudRate     = 115200;
    huart1.Init.WordLength   = UART_WORDLENGTH_8B;
    huart1.Init.StopBits     = UART_STOPBITS_1;
    huart1.Init.Parity       = UART_PARITY_NONE;
    huart1.Init.HwFlowCtl    = UART_HWCONTROL_NONE;
    huart1.Init.Mode         = UART_MODE_TX_RX;

    if (HAL_UART_Init(&huart1) != HAL_OK) {
        return -1;  /* 初始化失败 */
    }

    /* 验证 UART 状态：TE/TRE 位必须置位 */
    if (!(USART1->CR1 & USART_CR1_TE)) {
        return -2;  /* 发送使能未生效 */
    }

    /* 设置中断优先级：抢占 3，子优先级 0 */
    HAL_NVIC_SetPriority(USART1_IRQn, 3, 0);
    HAL_NVIC_EnableIRQ(USART1_IRQn);

    /* 启动中断接收：等待下一个字节 */
    uint8_t dummy;
    HAL_UART_Receive_IT(&huart1, &dummy, 1);

    return 0;  /* 成功 */
}

/* UART 接收完成回调 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == USART1) {
        /* 重新启用中断接收，形成持续监听 */
        static uint8_t next_byte;
        HAL_UART_Receive_IT(huart, &next_byte, 1);
        /* 此处可将 next_byte 送入环形缓冲区 */
    }
}

