/* === 重构前：大泥球式 I2C 驱动（重复 + 强耦合）=== */

/* BMP280 驱动：复制了完整的 I2C 时序 */
uint8_t bmp280_read_reg(uint8_t reg) {
    I2C1->CR1 |= I2C_CR1_START;        /* 起始条件 */
    while(!(I2C1->SR1 & I2C_SR1_SB));  /* 等 START 事件 */
    I2C1->DR = 0x76 << 1;              /* 设备地址+W */
    while(!(I2C1->SR1 & I2C_SR1_ADDR));/* 等 ADDR 事件 */
    (void)I2C1->SR2;
    I2C1->DR = reg;                     /* 寄存器地址 */
    while(!(I2C1->SR1 & I2C_SR1_BTF));  /* 等传输完成 */
    I2C1->CR1 |= I2C_CR1_START;         /* 重复起始 */
    I2C1->DR = (0x76 << 1) | 0x01;      /* 设备地址+R */
    while(!(I2C1->SR1 & I2C_SR1_ADDR));
    (void)I2C1->SR2;
    uint8_t val = I2C1->DR;             /* 读取数据 */
    I2C1->CR1 |= I2C_CR1_STOP;          /* 停止条件 */
    return val;
}

/* MPU6050 驱动：几乎同样的 I2C 时序，只是地址不同 */
uint8_t mpu6050_read_reg(uint8_t reg) {
    I2C1->CR1 |= I2C_CR1_START;
    while(!(I2C1->SR1 & I2C_SR1_SB));
    I2C1->DR = 0x68 << 1;    /* 不同的设备地址 */
    while(!(I2C1->SR1 & I2C_SR1_ADDR));
    (void)I2C1->SR2;
    I2C1->DR = reg;
    while(!(I2C1->SR1 & I2C_SR1_BTF));
    I2C1->CR1 |= I2C_CR1_START;
    I2C1->DR = (0x68 << 1) | 0x01;
    while(!(I2C1->SR1 & I2C_SR1_ADDR));
    (void)I2C1->SR2;
    uint8_t val = I2C1->DR;
    I2C1->CR1 |= I2C_CR1_STOP;
    return val;
}

/* === 重构后：分层架构（零重复 + 弱耦合）=== */

/* HAL 层：I2C 时序封装 */
static void i2c_hal_start(I2C_TypeDef *i2c) {
    i2c->CR1 |= I2C_CR1_START;
    while(!(i2c->SR1 & I2C_SR1_SB));
}

static void i2c_hal_send_byte(I2C_TypeDef *i2c, uint8_t byte) {
    i2c->DR = byte;
    while(!(i2c->SR1 & I2C_SR1_BTF));
}

static void i2c_hal_stop(I2C_TypeDef *i2c) {
    i2c->CR1 |= I2C_CR1_STOP;
}

/* 协议层：I2C 写寄存器组合操作 */
drv_status_t i2c_proto_write_reg(
    I2C_TypeDef *i2c, uint8_t addr,
    uint8_t reg, uint8_t data) {
    i2c_hal_start(i2c);
    i2c_hal_send_byte(i2c, (addr << 1) | 0x00);
    i2c_hal_send_byte(i2c, reg);
    i2c_hal_send_byte(i2c, data);
    i2c_hal_stop(i2c);
    return DRV_OK;
}

/* 应用层：BMP280 和 MPU6050 共享同一协议层 */
uint8_t bmp280_read_reg(uint8_t reg) {
    I2C_TypeDef *i2c = I2C1;
    i2c_hal_start(i2c);
    i2c_hal_send_byte(i2c, 0x76 << 1);
    i2c_hal_send_byte(i2c, reg);
    i2c_hal_start(i2c);
    i2c_hal_send_byte(i2c, (0x76 << 1) | 0x01);
    (void)i2c->SR2;
    uint8_t val = i2c->DR;
    i2c_hal_stop(i2c);
    return val;
}

uint8_t mpu6050_read_reg(uint8_t reg) {
    I2C_TypeDef *i2c = I2C1;
    i2c_hal_start(i2c);
    i2c_hal_send_byte(i2c, 0x68 << 1);
    i2c_hal_send_byte(i2c, reg);
    i2c_hal_start(i2c);
    i2c_hal_send_byte(i2c, (0x68 << 1) | 0x01);
    (void)i2c->SR2;
    uint8_t val = i2c->DR;
    i2c_hal_stop(i2c);
    return val;
}
